var GatewayQueryUtil = Class.create();
GatewayQueryUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {
	//Replaced with this._initGatewayConfigIfEmpty():
	/*query_config : {
		'include_filter' : false,
		'filters' : [],
		'refresh_token': '',
		'page_info' : {
			'page_size' : 0,
			'previous_page_start_cursor' : '',
			'previous_page_end_cursor' : '',
			'has_next_page' : true,
			'has_previous_page' : false
		},
		'sensors_to_read' : [],
		'expected_count' : 0,
		'data_source' : {
			'ts' : {} //ts: live data, tds: cached data
		}
	},*/

	/**
	 * Add a filter to your query, using one of several pre-specified sensor paths.
	 * This method can be called multiple times, to add multiple filters (all of which must
	 *  evaluate to true for a given machine to match this query condition).
	 * Not adding a filter at all will result in all endpoints matching the query. This may
	 *  result in an inordinate number of endpoints being returned, so be sure to set a page size
	 *  to avoid too large of a response payload.
	 *
	 *
	 * @param {("serialNumber"|"id"|"name"|"computerID"|"domainName"|"manufacturer"|"model"|
	 * "ipAddress"|"isVirtual"|"os.name"|"os.platform"|"os.windows.name"|"os.windows.type"|
	 * "os.windows.majorVersion"|"os.windows.releaseId"|"installedApplications.name"|
	 * "installedApplications.version")} path The path to the node containing the value to match on.
	 *
	 * @param {("EQ"|"LT"|"LTE"|"GT"|"GTE"|"CONTAINS"|"STARTS_WITH"|"ENDS_WITH"|
	 * "MATCHES"|"UPDATED_AFTER"|"READ_AFTER")} queryOperator - The operator by which to compare the given value to the field value.
	 * Note that not all operators are valid for all fields or data sources. If the operator is
	 *  not valid, the query will return an error. Pleast test your query (for example, in
	 *  something like a background script) before using it in a live environment.
	 * Here is a description for all valid operators:
	 * <ul>
	 *    <li>EQ: Equal to. The field value and specified values must be equal.<br />Note: To
	 *    do an "is NOT equal to" query, use the "EQ" operator and set the "negated" argument to true.</li>
	 *    <li>LT: Less than. The field value must be less than the specified value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>LTE: Less than or equal to. The field value must be less than or equal to the given
	 *    value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>GT: Greater than. The field value must be greater than the specified value. <br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>GTE: Greater than or equal to. The field value must be greater than or equal to the
	 *    given value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>CONTAINS: The string contains operator. The field value must contain the specified
	 *    value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>STARTS_WITH: The field value must start with the specified value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>ENDS_WITH: The field value must end with the specified value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>MATCHES: The field value must fully match the specified value, which is interpreted
	 *    as a regular expression in Perl syntax.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>UPDATED_AFTER: The field value must have been updated after the specified
	 *    (zulu-formatted) date and time.<br />
	 *    This is only valid for fields from certain data sources.</li>
	 *    <li>READ_AFTER: The field value must have been read/updated after the specified
	 *    (zulu-formatted) date and time.<br />
	 *    This is only valid for fields from certain data sources.</li>
	 * </ul>
	 *
	 * @param {String} value - The value to compare with the field value, expressed as a string.
	 * If this value cannot be interpreted as a valid value for the field type, the query will
	 *  return an error.
	 *
	 * @param {Boolean} [negated=false] - Optionally indicate the filter is negated, so that
	 *  records with field rows matching the filter will be <strong>excluded</strong> from the
	 *  query results.
	 *
	 * @return {GatewayQueryUtil} - Returns 'this' so you can chain API method calls.
	 *
	 * @example
	 * var tUtil = new x_taniu_tan_core.GatewayQueryUtil();
	 * //Only wait for one live machine matching the filter before returning response.
	 * tUtil.useLiveData(1);
	 * tUtil.addFilter('serialNumber', 'CONTAINS', 'VMware')
	 *    .addFilter('serialNumber', 'CONTAINS', '56')
	 *    .addFilter('id', 'EQ', '4');
	 *
	 * tUtil.addSensor('Computer Name');
	 *
	 * gs.debug(
	 *    JSON.stringify(
	 *       tUtil.getNextPage(), null, 2
	 *    )
	 * );
	 */
	addFilter: function(path, queryOperator, value, negated) {
		this._initGatewayConfigIfEmpty();
		if (!path || !queryOperator || !value) {
			throw new Error(
				'Attempted to add a filter, but failed to specify a valid filter path, ' +
				'queryOperator, or sensor.'
			);
		}
		negated = (typeof negated == 'undefined') ? false : !!negated;
		this.query_config.filters.push({
			'path': path,
			'op': queryOperator,
			'value': value,
			'negated': negated,
			'any': false //upcoming_feature: Add "any" argument to this method?
		});
		this.query_config.include_filter = true;
		return this;
	},

	/**
	 * Add a sensor-based filter to your query, filtering on any specified sensor's readings.
	 * This method can be called multiple times, to add multiple filters (ALL of which must
	 *  evaluate to true for a given machine to match this query condition).
	 * Not adding a filter at all will result in all endpoints matching the query. This may
	 *  result in an inordinate number of endpoints being returned, so be sure to set a page size
	 *  to avoid too large of a response payload.
	 *
	 *  NOTE: At present, this method only supports sensors which return a single column/value,
	 *   and which do not require any parameters to be passed to them.
	 *
	 * @param {String} sensorName - The precise name of the sensor that must have a result
	 *  matching the specified value based on the specified operator.
	 *
	 * @param {("EQ"|"LT"|"LTE"|"GT"|"GTE"|"CONTAINS"|"STARTS_WITH"|"ENDS_WITH"|
	 * "MATCHES"|"UPDATED_AFTER"|"READ_AFTER")} queryOperator - The operator by which to compare the given value to the field value.
	 * Note that not all operators are valid for all fields or data sources. If the operator is
	 *  not valid, the query will return an error. Please test your query (for example, in
	 *  something like a background script) before using it in a live environment.
	 *
	 * Here is a description for all valid operators:
	 * <ul>
	 *    <li>EQ: Equal to. The field value and specified values must be equal.<br />Note: To
	 *    do an "is NOT equal to" query, use the "EQ" operator and set the "negated" argument to true.</li>
	 *    <li>LT: Less than. The field value must be less than the specified value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>LTE: Less than or equal to. The field value must be less than or equal to the given
	 *    value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>GT: Greater than. The field value must be greater than the specified value. <br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>GTE: Greater than or equal to. The field value must be greater than or equal to the
	 *    given value.<br />
	 *    This is valid only for 'comparable' types.</li>
	 *    <li>CONTAINS: The string contains operator. The field value must contain the specified
	 *    value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>STARTS_WITH: The field value must start with the specified value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>ENDS_WITH: The field value must end with the specified value.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>MATCHES: The field value must fully match the specified value, which is interpreted
	 *    as a regular expression in Perl syntax.<br />
	 *    This is valid only for 'string' types.</li>
	 *    <li>UPDATED_AFTER: The field value must have been updated after the specified
	 *    (zulu-formatted) date and time.<br />
	 *    This is only valid for fields from certain data sources.</li>
	 *    <li>READ_AFTER: The field value must have been read/updated after the specified
	 *    (zulu-formatted) date and time.<br />
	 *    This is only valid for fields from certain data sources.</li>
	 * </ul>
	 *
	 * @param {String} value - The value to compare with the field value, expressed as a string.
	 * If this value cannot be interpreted as a valid value for the field type, the query will
	 *  return an error.
	 *
	 * @param {Boolean} [negated=false] - Optionally indicate the filter is negated, so that
	 *  records with field rows matching the filter will be <strong>excluded</strong> from the
	 *  query results.
	 *
	 * @return {GatewayQueryUtil} - Returns 'this' so you can chain API method calls.
	 *
	 * @example
	 * var queryResponse;
	 * var gquGetWatchlists = new x_taniu_tan_core.GatewayQueryUtil();
	 * //Use cached data to drastically reduce the time it takes to run the query.
	 * gquGetWatchlists.useCachedData();
	 *
	 * gquGetWatchlists.addSensor('Computer Name')
	 * gquGetWatchlists.addSensor('Integrity Monitor - Active Watchlists');
	 *
	 * gquGetWatchlists.addSensorFilter(
	 * 	'Integrity Monitor - Active Watchlists', //Sensor Name
	 * 	'EQ', //Operator (negated = "is NOT equal to")
	 * 	'N/A on Mac', //Value
	 * 	true //Negate the operator (i.e. "is NOT equal to")
	 * ).addSensorFilter(
	 * 	'Integrity Monitor - Active Watchlists', //Sensor Name
	 * 	'EQ', //Operator (negated = "is NOT equal to")
	 * 	'No Results Found', //Value
	 * 	true //Negate the operator (i.e. "is NOT equal to")
	 * );
	 *
	 * queryResponse = gquGetWatchlists.queryAsync();
	 *
	 * gs.debug(
	 * 	JSON.stringify(
	 * 		queryResponse, null, 2
	 * 	)
	 * );
	 */
	addSensorFilter: function(sensorName, queryOperator, value, negated) {
		this._initGatewayConfigIfEmpty();
		if (!sensorName || !queryOperator || !value) {
			throw new Error(
				'Attempted to add a filter, but failed to specify a valid filter sensorName, ' +
				'queryOperator, or sensor.'
			);
		}
		negated = (typeof negated == 'undefined') ? false : !!negated;
		this.query_config.filters.push({
			'sensor': {
				"name": sensorName
			},
			'op': queryOperator,
			'value': value,
			'negated': negated,
			'any': false //upcoming_feature: Add "any" argument to this method?
		});
		this.query_config.include_filter = true;
		return this;
	},

	/**
	 * Add a sensor to your query by specifying the exact name of the sensor in Tanium.
	 * Note that if using cached rather than live data (by calling .useCachedData()), if the
	 *  specified sensor is not "harvested" for TDS (Tanium Data Services), then this API call may
	 *  result in an error.
	 * @param {String} sensorName - The exact name of the Tanium sensor. For example, "Computer
	 *  Name" or "Computer Serial Number".
	 * If in doubt, use the Tanium Question Builder (/interact/buildquestion) to identify the
	 *  exact names of the sensors you may want to use.
	 * @param {Boolean} [allowDuplicates=false] - Set this to true if you need to add the same
	 *  sensor to this single query multiple times; for example, if you want to query the same
	 *  sensor twice with two different sets of parameters.
	 * @return {GatewayQueryUtil._Sensor} - An instance of the newly-created _Sensor object, with
	 *  the .addParam() method. You can either store a reference to this _Sensor object in a
	 *  variable and call the .addParam() method of that variable, or simply chain-call the
	 *  .addParam() method like so:
	 * gqUtil.addSensor('sensor_name').addParam('param_name', 'param_value');
	 * @example
	 * var tUtil = new x_taniu_tan_core.GatewayQueryUtil();
	 * //Only wait for one live machine matching the filter before returning response.
	 * tUtil.useLiveData(1);
	 * tUtil.addFilter('serialNumber', 'CONTAINS', 'VMware')
	 *    .addFilter('serialNumber', 'CONTAINS', '56')
	 *    .addFilter('id', 'EQ', '4');
	 * //Add several sensors, including one requiring multiple parameters.
	 * tUtil.addSensor('OS Platform');
	 * tUtil.addSensor('Computer Name');
	 * tUtil.addSensor('Performance - Top Process Metric Analysis')
	 *    .addParam('Number', '1')
	 *    .addParam('Metric', 'CPU Total')
	 *    .addParam('Analysis', 'Quantile')
	 *    .addParam('Hours', '24')
	 *    .addParam('Quantile', '0')
	 *    .addParam('Normalize', '0');
	 *
	 * gs.debug(
	 *    JSON.stringify(
	 *       tUtil.getNextPage(), null, 2
	 *    )
	 * );
	 */
	addSensor: function(sensorName, allowDuplicates) {
		var i, newSensor;
		this._initGatewayConfigIfEmpty();
		//Set default param value or coerce provided value to boolean
		allowDuplicates = (typeof allowDuplicates === 'undefined') ? false : !!allowDuplicates;

		if (!sensorName) {
			throw new Error(
				'Attempted to add a sensor to the query, but failed to specify a sensor name.'
			);
		}

		if (!allowDuplicates) {
			//If not allowing duplicate sensors, check if this sensor already exists.
			for (i = 0; i < this.query_config.sensors_to_read.length; i++) {
				if (sensorName === this.query_config.sensors_to_read[i].name) {
					//If the sensor already exists, log an error and
					gs.error(
						'Attempted to add Tanium sensor "' + sensorName + '" to API Gateway ' +
						'query. However, that sensor is already part of this query.\n' +
						'You can allow duplicate sensor names by specifying a second argument ' +
						'(allowDuplicates) when calling GatewayQueryUtil.addSensor(), and ' +
						'setting that argument to the boolean true.'
					);
					return this.query_config.sensors_to_read[i];
				}
			}
		}
		newSensor = new this._Sensor(sensorName);
		this.query_config.sensors_to_read.push(
			newSensor
		);
		//Return reference to newly created sensor object for chaining .addParam() calls.
		return newSensor;
	},

	/**
	 * Tell this query to use live, rather than cached data.
	 *
	 * @param {Number} [expectedCount=0] - The number of endpoints to await. If you're not sure
	 *  how many endpoints you're expecting to respond, you can set this to 0, and it will be
	 *  ignored, if you prefer to use stableWaitTime; or you can not specify either, and the
	 *  server defaults will be used.
	 *
	 * @param {Number} [stableWaitTime=0] - The number of seconds allowed to elapse without the
	 *  server receiving new endpoint results. Once this number of seconds have elapsed following
	 *  the most recent endpoint to respond, any results from endpoints that <i>have</i> responded
	 *  will be included and the result will be returned.
	 *
	 * @return {GatewayQueryUtil} - Returns 'this' so you can chain API method calls.
	 */
	useLiveData: function(expectedCount, stableWaitTime) {
		this._initGatewayConfigIfEmpty();
		this.query_config.data_source = {
			'ts': {
				"excludeErrors": this.query_config.excludeErrors || false,
				"excludeNoResults": this.query_config.exclude_no_results || false
			}
		};
		if (expectedCount) {
			this.query_config.data_source.ts.expectedCount = expectedCount;
		}
		if (stableWaitTime) {
			this.query_config.data_source.ts.stableWaitTime = stableWaitTime;
		}
		return this;
	},

	/**
	 * Tell this query to use cached, rather than live data. Cached data is pulled from TDS
	 *  (Tanium Data Services), and any sensors used must be harvested for inclusion in TDS or
	 *  this query may return an error.
	 * @return {GatewayQueryUtil} - Returns 'this' so you can chain API method calls.
	 */
	useCachedData: function() {
		this._initGatewayConfigIfEmpty();
		this.query_config.data_source = {
			'tds': {
				"allNamespaces": true,
				"excludeErrors": this.query_config.excludeErrors || false,
				"excludeNoResults": this.query_config.exclude_no_results || false
			}
		};
		return this;
	},

	/**
	 * Set the page size for this query. Only up to this number of results will be returned.
	 * If there are more than this number of results available, the response's
	 *  data.endpoints.pageInfo.hasNextPage node will be set to true, and you can call
	 *  .getNextPage() to get the next page of results.
	 *
	 * This will set the property "first" in the "endpoints" node of the resultant GQL query body.
	 * @param {Number} newPageSize - An integer representing the number of endpoints to retrieve
	 *  (up to the expectedCount, if using live data) per "page". Call .getNextPage() again to
	 *  get the next page automatically.
	 * @return {GatewayQueryUtil} - Returns 'this' so you can chain API method calls.
	 */
	setPageSize: function(newPageSize) {
		this._initGatewayConfigIfEmpty();
		if (typeof newPageSize !== 'number') {
			throw new Error(
				'.setPageSize() method called with non-numerical argument, "' + newPageSize +
				'". Only integers are allowed.'
			);
		}
		//ensure that
		this.query_config.page_info.page_size = parseInt(newPageSize.toFixed());
		return this;
	},

	/**
	 * Retrieve the current query configuration object.
	 * @returns {*|{include_filter: boolean, refresh_token: string, page_info: {has_previous_page:
	 *     boolean, previous_page_start_cursor: string, previous_page_end_cursor: string,
	 *     has_next_page: boolean, page_size: number}, sensors_to_read: *[], expected_count:
	 *     number, filters: *[], data_source: {ts: {}}}}
	 */
	getQueryConfig: function() {
		this._initGatewayConfigIfEmpty();
		return this.query_config;
	},

	/**
	 * Manually set the "cursor" (where to begin the next page query).
	 * This will only really be necessary if you're somehow passing off the query between one page
	 * and another, to a new script or context.
	 * @param {String} newCursor - The new "cursor" location (where to begin the next page query).
	 * Example: .setCursor('2222775:1907365970:2');
	 * @return {GatewayQueryUtil}
	 */
	setCursor: function(newCursor) {
		this._initGatewayConfigIfEmpty();
		if (typeof newCursor !== 'string') {
			throw new Error(
				'.setCursor() called with invalid argument. Expected a string with the cursor ' +
				'value from a previous query. Example: "2214657:2480081680:0"'
			);
		}
		this.query_config.page_info.previous_page_end_cursor = newCursor;
		return this;
	},

	/**
	 * Retrieve the refresh token for the current query.
	 * This should typically not be necessary, unless you need to pass the refresh token for
	 *  the current query into the .refreshQueryWithToken() method of a new instance of the
	 *  GatewayQueryUtil class. If refreshing the query by token using the same instance of this
	 *  class that was used to initiate the query (using .initQueryGetTokenAsync()), then the
	 *  instance will already have the refresh token, as it is retained in the instance's query
	 *  configuration object, which can be inspected by calling the .getQueryConfig() method.
	 * @returns {String}
	 */
	getRefreshToken: function() {
		return this.query_config.page_info.refresh_token;
	},

	/**
	 * AFTER calling .getNextPage(), get the cursor position representing the end of the current
	 *  "page" of results.
	 * This will only really be necessary if you're somehow passing off the query between one page
	 *  and another, to a new script or context.
	 * @return {string} - The current cursor, as a string.
	 */
	getCursor: function() {
		this._initGatewayConfigIfEmpty();
		return this.query_config.page_info.previous_page_end_cursor;
	},

	/**
	 * Get a boolean representing whether there is a "next" page of results to your query.
	 * @return {boolean} - True if there is a "next" page of results, or false if not.
	 * Only provides meaningful data AFTER calling .getNextPage() at least once. Otherwise, always
	 *  returns true.
	 */
	hasNextPage: function() {
		this._initGatewayConfigIfEmpty();
		return this.query_config.page_info.has_next_page;
	},

	/**
	 * Execute the query and get the next (or first) page of results.
	 * Calling this method will automatically update the page info, so you can call
	 *  .getNextPage() again to get the next page (if .hasNextPage() returns true).
	 *
	 * @param {boolean} [executeAsync=this.rest_async] - If set to true, the .executeAsync() method of
	 *  RESTMessageV2 will be used instead of the .execute() method. This may result in a longer
	 *  time between call and response, but may be preferable if the total number of requests is
	 *  very high, which could otherwise bog down instance performance.
	 *
	 * If not specified, this argument defaults to the value of this.rest_async, which initializes
	 *  to false but can be set using the .setRESTAsync() method. Specifying the executeAsync argument here, overrides the behavior set by calling .setRESTAsync().
	 *
	 * See this link to ServiceNow's API documentation on .executeAsync():
	 * https://developer.servicenow.com/dev.do#!/reference/api/sandiego/server/sn_ws-namespace/c_RESTMessageV2API#r_RMV2-executeAsync
	 *
	 * @return {Object|Boolean}
	 */
	getNextPage: function(executeAsync) {
		this._initGatewayConfigIfEmpty();
		var rQueryGateway,
			sensorsSerialized,
			sourceSerialized,
			pageSize,
			afterCursor,
			responseBody;
		var filtersSerialized = '';
		var readyStatus = this._isReadyToSend();
		//Set default value of executeAsync
		executeAsync = (typeof executeAsync == 'undefined') ? this.rest_async : !!executeAsync;

		if (!readyStatus.ready) {
			throw new Error(
				'API Gateway query not ready to send. \n' +
				JSON.stringify(readyStatus, null, 2)
			);
		}

		rQueryGateway = this._getRESTObject( //Inherited from TaniumIntegrationCore
			'Tanium Integration Core',
			'Gateway-Query Sensors'
		);
		rQueryGateway.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);

		pageSize = this.query_config.page_info.page_size;
		afterCursor = this.query_config.page_info.previous_page_end_cursor || '';
		afterCursor = afterCursor ? ('after:\\"' + afterCursor) + '\\"' : '';
		sourceSerialized = this._serializeObjectForGQL(this.query_config.data_source).replaceAll(
			'"',
			'\\"'
		);
		sensorsSerialized = this._serializeObjectForGQL(this.query_config.sensors_to_read).replaceAll(
			'"',
			'\\"'
		);

		if (this.query_config.include_filter && this.query_config.filters) {
			filtersSerialized = 'filter:{filters:' + (this._serializeFiltersForGQL(this.query_config.filters).replaceAll(
				'"',
				'\\"'
			)) + '}';
		}

		rQueryGateway.setStringParameterNoEscape('page_size', pageSize);
		rQueryGateway.setStringParameterNoEscape('after_cursor', afterCursor);
		rQueryGateway.setStringParameterNoEscape('source_serialized', sourceSerialized);
		rQueryGateway.setStringParameterNoEscape('sensors_serialized', sensorsSerialized);
		rQueryGateway.setStringParameterNoEscape('filters_serialized', filtersSerialized);
		//Inherited from TaniumIntegrationCore

		responseBody = this._executeRESTCall(rQueryGateway, false, true, false, executeAsync);

		if (
			!(
				responseBody.hasOwnProperty('data') &&
				responseBody.data
			) ||
			!(
				responseBody.data.hasOwnProperty('endpoints') &&
				responseBody.data.endpoints
			) ||
			!(
				responseBody.data.endpoints.hasOwnProperty('pageInfo') &&
				responseBody.data.endpoints.pageInfo
			) ||
			!(
				responseBody.data.endpoints.pageInfo.hasOwnProperty('startCursor') &&
				responseBody.data.endpoints.pageInfo.startCursor
			)
			//endCursor is not always returned, so we can't rely on it.
			/* ||
			!(
				responseBody.data.endpoints.collectionInfo.hasOwnProperty('endCursor') &&
				responseBody.data.endpoints.collectionInfo.endCursor
			) */
		) {
			throw new Error('Invalid response body from Tanium API Gateway:\n' + JSON.stringify(
				responseBody,
				null,
				2
			));
		}
		//Update local page_info config info to prepare for next page, if necessary.
		this.query_config.page_info.previous_page_start_cursor = (
			responseBody.data.endpoints.pageInfo.startCursor ||
			responseBody.data.endpoints.collectionInfo.startCursor ||
			null
		);
		this.query_config.page_info.previous_page_end_cursor = (
			responseBody.data.endpoints.pageInfo.endCursor ||
			responseBody.data.endpoints.collectionInfo.endCursor ||
			null
		);
		this.query_config.page_info.has_next_page = responseBody.data.endpoints.pageInfo.hasNextPage || false;
