	 *
	 * 	if (!refreshToken) {
	 * 		throw new Error(
	 * 			'No refresh token found for query with the following config: \n' +
	 * 			JSON.stringify(gqu.getQueryConfig(), null, 2)
	 * 		);
	 * 	}
