	 * 		'Attempt ' + currentLoop + ' got ' +
	 * 		queryResponse.data.endpoints.collectionInfo.respondedPercentage +
	 * 		' responded percentage (' +
	 * 		queryResponse.data.endpoints.collectionInfo.respondedPercentage + '/' +
	 * 		queryResponse.data.endpoints.collectionInfo.respondedTotal + ').\n' +
	 * 		JSON.stringify(
	 * 			queryResponse.data.endpoints.collectionInfo,
	 * 			null,
	 * 			2
	 * 		)
	 * 	);
	 * 	gs.debug(
	 * 		'Response body:\n' +
	 * 		JSON.stringify(queryResponse, null, 2)
	 * 	);
	 *
	 * 	percentResponded = +queryResponse.data.endpoints.collectionInfo.respondedPercentage;
	 * 	responseCount = queryResponse.data.endpoints.edges.length;
	 * 	currentLoop++;
	 * }
	 *
	 * gs.debug('COMPLETE after ' + (currentLoop - 1) + ' loops: \n' +
	 * 	JSON.stringify(
	 * 		queryResponse,
	 * 		null,
	 * 		2
	 * 	)
	 * );
