	initQueryGetTokenAsync: function(executeAsync, maxWaitTime, expectedCount) {
		this._initGatewayConfigIfEmpty();

		var rQueryGateway, responseBody, queryConfig, sensorsSerialized;
		var readyStatus = this._isReadyToSend();

		executeAsync = (typeof executeAsync === 'undefined') ? this.rest_async : !!executeAsync;
		maxWaitTime = (typeof maxWaitTime === 'number') ? maxWaitTime : 5;
		expectedCount = (typeof expectedCount === 'number') ? expectedCount : 0;

		if (!readyStatus.ready) {
			throw new Error(
				'API Gateway query not ready to send with .initQueryGetTokenAsync() method. Ready status:\n' +
				JSON.stringify(readyStatus, null, 2)
			);
		}

		//Set query config object to be used to populate the GQL query variables.
		queryConfig = this._getInitialTokenQueryVariables(maxWaitTime, expectedCount);
		sensorsSerialized = this._serializeObjectForGQL(this.query_config.sensors_to_read).replaceAll(
			'"',
			'\\"'
		);

		rQueryGateway = this._getRESTObject( //Inherited from TaniumIntegrationCore
			'Tanium Integration Core',
			'Gateway-Query with Refresh Token'
		);
		rQueryGateway.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rQueryGateway.setStringParameterNoEscape(
			'sensors_serialized', sensorsSerialized
		);
		rQueryGateway.setStringParameterNoEscape(
			'query_variables_object',
			JSON.stringify(queryConfig)
		);


		responseBody = this._executeRESTCall(
			rQueryGateway,
			false,
			true,
			false,
			executeAsync
		);


		if (
			!(
				responseBody.hasOwnProperty('data') &&
				responseBody.data
			) ||
			!(
				responseBody.data.hasOwnProperty('endpoints') &&
				responseBody.data.endpoints
			) ||
			!(
				responseBody.data.endpoints.hasOwnProperty('collectionInfo') &&
				responseBody.data.endpoints.collectionInfo
			) ||
			!(
				responseBody.data.endpoints.collectionInfo.hasOwnProperty('startCursor') &&
				responseBody.data.endpoints.collectionInfo.startCursor
			)
		) {
			throw new Error('Invalid response body from Tanium API Gateway:\n' + JSON.stringify(
				responseBody,
				null,
				2
			));
		}

		//Update local page_info config info to prepare for token refresh, if necessary.
		this.query_config.page_info.refresh_token = responseBody.data.endpoints.collectionInfo.startCursor;
		this.query_config.page_info.previous_page_start_cursor = responseBody.data.endpoints.collectionInfo.startCursor;
		this.query_config.page_info.previous_page_end_cursor = responseBody.data.endpoints.collectionInfo.endCursor;
		this.query_config.page_info.has_next_page = responseBody.data.endpoints.pageInfo.hasNextPage || false;
		this.query_config.page_info.has_previous_page = responseBody.data.endpoints.pageInfo.hasPreviousPage || false;

		return responseBody;
	},


	/**
