				JSON.stringify(readyStatus, null, 2)
			);
		}

		//Set query config object to be used to populate the GQL query variables.
		queryConfig = this._getInitialTokenQueryVariables(maxWaitTime, expectedCount);
		sensorsSerialized = this._serializeObjectForGQL(this.query_config.sensors_to_read).replaceAll(
