			'\\"'
		);

		//Add refresh token to query config object.
		queryConfig.refreshCursor = refreshToken;

		rQueryGateway = this._getRESTObject( //Inherited from TaniumIntegrationCore
			'Tanium Integration Core',
			'Gateway-Query with Refresh Token'
		);
		rQueryGateway.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rQueryGateway.setStringParameterNoEscape('sensors_serialized', sensorsSerialized);
		rQueryGateway.setStringParameterNoEscape(
			'query_variables_object',
			JSON.stringify(queryConfig)
		);

		responseBody = this._executeRESTCall(
			rQueryGateway,
			false,
			true,
			false,
			executeAsync
		);

		if (
			!(
				responseBody.hasOwnProperty('data') &&
				responseBody.data
			) ||
			!(
				responseBody.data.hasOwnProperty('endpoints') &&
				responseBody.data.endpoints
			) ||
			!(
				responseBody.data.endpoints.hasOwnProperty('collectionInfo') &&
				responseBody.data.endpoints.collectionInfo
			) ||
			!(
				responseBody.data.endpoints.collectionInfo.hasOwnProperty('startCursor') &&
				responseBody.data.endpoints.collectionInfo.startCursor
			)
		) {
