		this.query_config.page_info.previous_page_start_cursor = responseBody.data.endpoints.collectionInfo.startCursor;
		this.query_config.page_info.previous_page_end_cursor = responseBody.data.endpoints.collectionInfo.endCursor;
		this.query_config.page_info.has_next_page = responseBody.data.endpoints.pageInfo.hasNextPage || false;
		this.query_config.page_info.has_previous_page = responseBody.data.endpoints.pageInfo.hasPreviousPage || false;

		return responseBody;
