	queryAsync: function(
		minimumEndpointCount,
		minimumResponsePercent,
		maxRetries,
		executeAsync,
		expectedCount,
		maxWaitTimePerRequest,
		requireAvailableResults
	) {
		var readyStatus, queryResponse, respondedPercent, respondedCount;
		var iCurrentLoop = 1;

		minimumEndpointCount = (typeof minimumEndpointCount === 'number') ? minimumEndpointCount : 0;
		minimumResponsePercent = (typeof minimumResponsePercent === 'number') ? minimumResponsePercent : 1;
		executeAsync = (typeof executeAsync !== 'undefined') ? executeAsync : false;
		expectedCount = (typeof expectedCount === 'number') ? expectedCount : 0;
		requireAvailableResults = (typeof requireAvailableResults !== 'undefined') ? !!requireAvailableResults : false;

		//Ensure a valid value for maxWaitTimePerRequest (>=2 and <30). If not, use default value (5).
		if (typeof maxWaitTimePerRequest !== 'number' || maxWaitTimePerRequest < 2 || maxWaitTimePerRequest >= 30) {
			maxWaitTimePerRequest = 5;
		}

		/* Default value for maxRetries is 180 seconds (3 minutes) divided by maxWaitTimePerRequest.
		For example, if maxWaitTimePerRequest is 5, maxRetries will be 36 to equal a maximum of
		3 minutes.
		Default value will be used if maxRetries is not a number or is less than 1. */
		maxRetries = (typeof maxRetries === 'number' && maxRetries > 0) ? maxRetries : (180 / maxWaitTimePerRequest);

		//Ensure a valid value for minimumResponsePercent. If >1, divide by 100 to get a percentage.
		if (minimumResponsePercent > 1) {
			if (minimumResponsePercent > 100) {
				gs.warn(
					'queryAsync() minimumResponsePercent value is greater than 100. Value ' +
					'should be between 0 and 1. \n' +
					'If set to >1, it will be divided by 100 to get the percentage. However, if ' +
					'>100, it will be ignored.'
				);
				minimumResponsePercent = 1;
			} else {
				gs.debug(
					'queryAsync() minimumResponsePercent value is greater than 1. Value ' +
					'should be between 0 and 1. \n' +
					'If set to >1 && <100, it will be divided by 100 to get the percentage.'
				);
				minimumResponsePercent = minimumResponsePercent / 100;
			}
		}

		//Ensure the query is ready to send. If not, throw an error.
		readyStatus = this._isReadyToSend();
		if (!readyStatus.ready) {
			throw new Error(
				'API Gateway query not ready to send. \n' +
				JSON.stringify(readyStatus, null, 2)
			);
		}

		queryResponse = this.initQueryGetTokenAsync(
			executeAsync,
			maxWaitTimePerRequest,
			expectedCount
		);


		try {
			//Use Unary plus operator to ensure value is a number.
			respondedPercent = +queryResponse.data.endpoints.collectionInfo.respondedPercentage || 0;
			respondedCount = queryResponse.data.endpoints.edges.length || 0;
		} catch(ex) {
			//If unable to parse the response, set count and percent to 0 and try again.
			respondedPercent = 0;
			respondedCount = 0;
		}

		/*
			If using LIVE rather than cached data, loop until one of the following conditions is met:
				1. The number of endpoints that have responded is greater than or equal to the minimumEndpointCount (IF minimumEndpointCount is specified).
				2. The percentage of endpoints that have responded is greater than or equal to the minimumResponsePercent (IF minimumResponsePercent is specified).
				3. The number of retries has exceeded the maxRetries value.

			Note that if requireAvailableResults is true, then the response will not be returned until "current" results are available for all sensors in the query, unless maxRetries is reached. If maxRetries is reached, then the response will be returned regardless of whether current results are available for all sensors.

			This logic is only relevant when using live data, as cached data should always have current results available.
		 */
		if (!this._isUsingCachedData()) {
			while (
				(iCurrentLoop <= maxRetries) &&
				(
					(
						(minimumEndpointCount ? (respondedCount < minimumEndpointCount) : true) &&
						(minimumResponsePercent ? (respondedPercent < minimumResponsePercent) : true)
					) || (
						requireAvailableResults ? (
							this._containsResultsUnavailable(
								queryResponse,
								true
							)
						) : false
					)
				)
				) {
				queryResponse = this.refreshQueryWithToken(
					this.getRefreshToken(),
					executeAsync,
					maxWaitTimePerRequest,
					expectedCount
				);

				//Unary plus operator to ensure value is a number.
				try {
					respondedPercent = +queryResponse.data.endpoints.collectionInfo.respondedPercentage || 0;
					respondedCount = queryResponse.data.endpoints.edges.length || 0;
				} catch (ex) {
					//If unable to parse the response, set count and percent to 0 and try again.
					respondedPercent = 0;
					respondedCount = 0;
				}

				gs.debug(
					'queryAsync() loop #' + iCurrentLoop + ' of ' + maxRetries + '.\n' +
					respondedCount + ' of ' + minimumEndpointCount + ' endpoints included in results.\n' +
					respondedPercent + ' of ' + (minimumResponsePercent * 100) +
					'% of endpoints responded.\n' +
					'Current refresh token (non-sensitive): ' + this.getRefreshToken() + '\n' +
					'queryResponse: ' + JSON.stringify(queryResponse, null, 2)
				);

				iCurrentLoop++;
			}

			if ( //If stopping conditions weren't met, throw a message into the debug log.
				(
					(
						(minimumEndpointCount ? (respondedCount < minimumEndpointCount) : true) &&
						(minimumResponsePercent ? (respondedPercent < minimumResponsePercent) : true)
					) || (
						requireAvailableResults ? (
							this._containsResultsUnavailable(
								queryResponse,
								true
							)
						) : false
					)
				)
			) {
				gs.debug(
					'GatewayQueryUtil.queryAsync() did not meet stopping conditions before ' +
					'hitting the maximum number of loops (' + maxRetries + ').'
				);
			} else {
				gs.debug(
					'GatewayQueryUtil.queryAsync() met stopping conditions in ' +
					(iCurrentLoop) + ' loop(s), before exceeding the maximum (' + maxRetries + ').'
				);
			}
		} else {
			//If using cached data, only one request is needed as the data should be immediately available.

			//Commented out since we're already getting the response from the initial query much earlier in this method.
			/* queryResponse = this.refreshQueryWithToken(
				this.getRefreshToken(),
				executeAsync,
				maxWaitTimePerRequest,
				expectedCount
			); */
		}

		return queryResponse;
	},

	/**
	 * This method will take the results of a query from the Tanium API Gateway (using either .queryAsync() or .getNextPage()), and transform it into a more readable and comprehensible format, suitable for use in ServiceNow or for display to a user.<br />
	 * <br />
	 * Note that this method is still in beta. It has been tested internally with a variety of single and multi-row sensors, but it should still be considered in 'beta', and tested before use.
	 * Although we are not aware of any specific issues or incompatibilities, it's possible that it may not work as expected with all sensors. It is recommended to test this method with any sensors you intend to use it with, and to verify that the transformation is working as expected.
	 *
	 * @param {Object} responseObj - The response object from the Tanium API Gateway, as returned by the .queryAsync() or .getNextPage() methods.
	 * @param {boolean} [removeNoResultRows=true] - If true, rows with "[no results]" will be removed.
	 *
	 * @returns {{columns: *[], rows: *[]}}
	 * @beta
	 * @stability beta - This method is still in beta, though it is expected to be stable. <br />
	 * The INTENTION is for it to not be removed or changed in a way that is not backwards-compatible with any use-case in which this transformation may be considered fully working. It should only be modified in order to resolve potential bugs relating to rare and unexpected edge cases caused by sensors which return unexpected data that may be incompatible with the transformation process.
	 * While in beta, it is strongly recommended to test this method with any sensors you intend to use it with and to verify that the transformation is working as expected. It is also recommended to test this method with a variety of single and multi-row sensors, and to verify that the transformation is working as expected, as this method has been tested more with single-row sensors (such as "Computer Name" or "Computer Serial Number") than with multi-row sensors (such as "Installed Applications" or "Running Processes").
	 */
	transformGatewayResponse: function(responseObj, removeNoResultRows) {
		return this._transformGatewayQueryResponseV2(responseObj, removeNoResultRows);
	},

	/**
	 * Call this method to exclude rows with "[no results]" from the response.
	 *
	 * Works when querying either live or cached data.
	 *
	 * @param {boolean} [excludeNoResults=true] - If this argument is set to true (or if unspecified),
	 *  then rows with "[no results]" will be removed from the response.
	 * If set to false (or if you don't call this method at all), then they will not be removed.
	 *
	 * @returns {GatewayQueryUtil} - Returns the instance of the GatewayQueryUtil object to
	 *  allow for method chaining.
	 *
	 * @example
	 * var queryResponse;
	 * var gquGetWatchlists = new x_taniu_tan_core.GatewayQueryUtil();
	 * //Use cached data to drastically reduce the time it takes to run the query.
	 * gquGetWatchlists.useCachedData();
	 *
	 * gquGetWatchlists.addSensor('Computer Name')
	 * gquGetWatchlists.addSensor('Computer Serial Number');
	 *
	 * gquGetWatchlists.excludeNoResults(false);
	 *
	 * queryResponse = gquGetWatchlists.queryAsync();
	 *
	 * gs.debug(
	 * 	JSON.stringify(
	 * 		queryResponse, null, 2
	 * 	)
	 * );
	 */
	excludeNoResults: function(excludeNoResults) {
		var sourceObj;

		//If excludeNoResults is not specified, default to true.
		excludeNoResults = (typeof excludeNoResults !== 'undefined') ? !!excludeNoResults : true;

		if (this.query_config.data_source.hasOwnProperty('ts')) {
			sourceObj = this.query_config.data_source.ts;
		} else {
			sourceObj = this.query_config.data_source.tds;
		}

		sourceObj.excludeNoResults = !!excludeNoResults;

		return this;
	},

	/**
	 * upcoming_feature: test and document this method.
	 * Call this method to exclude all endpoints that contain common error values in
	 *  ANY requested sensor data.
	 *
	 * This method must be called AFTER calling either .useLiveData() or .useCachedData() to
	 *  set your data source.
	 *
	 * Works when querying either live or cached data.
	 *
	 * @param {boolean} [excludeErrors=true] - If this argument is set to true (or if unspecified),
	 *  then rows with "[no results]" will be removed from the response.
	 * If set to false (or if you don't call this method at all), then they will not be removed.
	 */
	__wip_excludeErrors: function(excludeErrors) {
		var sourceObj;

		//If excludeErrors is not specified, default to true.
		excludeErrors = (typeof excludeErrors !== 'undefined') ? !!excludeErrors : true;

		if (this.query_config.data_source.hasOwnProperty('ts')) {
			sourceObj = this.query_config.data_source.ts;
		} else {
			sourceObj = this.query_config.data_source.tds;
		}

		sourceObj.excludeErrors = !!excludeErrors;

		return this;
	},

	//***** PRIVATE HELPER METHODS BELOW *****/

	_containsResultsUnavailable: function(response, includeResultsCurrentlyUnavailable) {
		var iEndpoint, iColumn, iValue, responseColumns, endpoints;

		includeResultsCurrentlyUnavailable = (
			typeof includeResultsCurrentlyUnavailable !== 'undefined'
		) ? !!includeResultsCurrentlyUnavailable : false;

		//Verify the response object is valid. If not, return false as an invalid response does
		// not contain "[current result unavailable]". It is not this method's job to detect
		// invalid responses, only to detect whether a valid response contains "[current result
		// unavailable]".
		if (
			typeof response !== 'object' ||
			!response.hasOwnProperty('data') ||
			!response.data ||
			!response.data.hasOwnProperty('endpoints') ||
			!response.data.endpoints ||
			!response.data.endpoints.hasOwnProperty('edges') ||
			!response.data.endpoints.edges
		) {
			gs.debug(
				'GatewayQueryUtil._containsCurrentResultUnavailable() received invalid response ' +
				'object with no data.endpoints.edges node. Returning false.'
			);
			return false;
		}

		endpoints = response.data.endpoints.edges;

		for (iEndpoint = 0; iEndpoint < endpoints.length; iEndpoint++) { //For each endpoint (edge)...
			responseColumns = endpoints[iEndpoint].node.sensorReadings.columns;
			if (!responseColumns || responseColumns.length === 0) {
				continue;
			}
			for (iColumn = 0; iColumn < responseColumns.length; iColumn++) { //For each column...
				if (
					!responseColumns[iColumn] ||
					!responseColumns[iColumn].hasOwnProperty('values') ||
					!responseColumns[iColumn].values ||
					responseColumns[iColumn].values.length === 0
				) {
					continue;
				}
				for (iValue = 0; iValue < responseColumns[iColumn].values.length; iValue++) { //For each value...
					if (
						responseColumns[iColumn].values[iValue] === '[current result unavailable]' ||
						(
							includeResultsCurrentlyUnavailable &&
							responseColumns[iColumn].values[iValue] === '[results currently unavailable]'
						)
					) {
						return true;
					}
				}
			}
		}

		return false;
	},

	/**
	 * @param maxWaitTime
	 * @param expectedCount
	 * @private
	 */
	_getInitialTokenQueryVariables: function(maxWaitTime, expectedCount) {
		var queryConfig;

		maxWaitTime = (typeof maxWaitTime === 'number') ? maxWaitTime : 5;
		expectedCount = (typeof expectedCount === 'number') ? expectedCount : 0;

		queryConfig = {
			'pageSize': this.query_config.page_info.page_size || null,
			'startCursor': null,
			'refreshCursor': null,
			//Default to live data if we can't find a data source in the local config for some reason
			'source': this.query_config.data_source || {
				'ts': {
					'maxWaitTime': maxWaitTime,
					'expectedCount': expectedCount,
					'excludeErrors': false,
					'excludeNoResults': false
				}
			},
			'filtersArray': (this.query_config.include_filter && this.query_config.filters) ? this.query_config.filters : []
		};

		//Override data source if retrieving live data (source is ts) to use
		// expectedCount/maxWaitTime.
		if (queryConfig.source.hasOwnProperty('ts')) {
			queryConfig.source.ts = {
				'maxWaitTime': maxWaitTime,
				'expectedCount': expectedCount
			};
		}
		//If filtersArray is blank, then use serial matches ".*".
		if (!queryConfig.filtersArray || queryConfig.filtersArray.length === 0) {
			queryConfig.filtersArray = [
				{
					'path': 'serialNumber',
					'op': 'MATCHES',
					'value': '.*',
					'negated': false,
					'any': false
				}
			];
		}

		return queryConfig;
	},

	/**
	 * @return {{ready: boolean, warnings: *[], has_warning: boolean, errors: *[], has_error:
	 *     boolean}}
	 * @private
	 */
	_isReadyToSend: function() {
		this._initGatewayConfigIfEmpty();
		var i, filterPath, filterOp;
		var returnObj = {
			'ready': true,
			'has_error': false,
			'has_warning': false,
			'errors': [],
			'warnings': []
		};
		var validFilterOperations = [
			'EQ',
			'LT',
			'LTE',
			'GT',
			'GTE',
			'CONTAINS',
			'STARTS_WITH',
			'ENDS_WITH',
			'MATCHES'
		];
		var validFilterPaths = [
			'serialNumber',
			'id',
			'name',
			'computerID',
			'domainName',
			'manufacturer',
			'model',
			'ipAddress',
			'isVirtual',
			'os.name',
			'os.platform',
			'os.windows.name',
			'os.windows.type',
			'os.windows.majorVersion',
			'os.windows.releaseId',
			'installedApplications.name',
			'installedApplications.version'
		];
		//Check if this.sensors_to_read is not empty
		if (
			!this.query_config.sensors_to_read ||
			this.query_config.sensors_to_read.length === 0
		) {
			returnObj.ready = false;
			returnObj.has_error = true;
			returnObj.errors.push(
				'No sensor to read from has been specified. Please call .addSensor() to add a ' +
				'sensor to be read.'
			);
		}
		//Check if filter is specified. If so, check that filter object is populated and valid.
		if (this.query_config.include_filter) {
			for (i = 0; i < this.query_config.filters.length; i++) {
				if (
					(!this.query_config.filters[i].path && !this.query_config.filters[i].sensor) ||
					!this.query_config.filters[i].op ||
					!this.query_config.filters[i].value
				) {
					returnObj.ready = false;
					returnObj.has_error = true;
					returnObj.errors.push(
						'include_filter is true, meaning a filter was specified, but is malformed. Possibly the filter path, op, or value, were not specified. \nFilter object: \n' + JSON.stringify(
							this.query_config.filter,
							null,
							2
						));
					//Abort this loop and go to the next one.
					continue;
				}

				if (this.query_config.filters[i] && this.query_config.filters[i].hasOwnProperty('path')) {

					//If the filter is a path-based filter (or rather, is not a sensor-based filter), then
					// check that the filter path is specified, and is a valid path.
					if (!this.query_config.filters[i].hasOwnProperty('sensor')) {
						filterPath = this.query_config.filters[i].path || '';
						if (validFilterPaths.indexOf(filterPath) < 0) {
							returnObj.ready = false;
							returnObj.has_error = true;
							returnObj.errors.push(
								'Filter path "' + filterPath + '" is not valid. Only the following ' +
								'filter paths are valid: \n' + validFilterPaths.join(', ') + '\n\n' +
								'Note: If you\'re trying to filter by a sensor, use a sensor-based filter ' +
								'instead of a path-based filter by calling the .adddSensorFilter() method.'
							);
						}
					}

					//Check that all filter operations are valid.
					filterOp = this.query_config.filters[i].op;
					if (validFilterOperations.indexOf(filterOp) < 0) {
						returnObj.ready = false;
						returnObj.has_error = true;
						returnObj.errors.push(
							'Filter operation "' + filterOp + '" is not valid. Only the following ' +
							'filter paths are valid: \n' + validFilterOperations.join(', ')
						);
					}
				}
			}
		}
		return returnObj;
	},

	/**
	 * Used for edges.node.sensorReadings.sensors objects, and the data source object.
	 * For the filters array, special parsing to handle enum rows is required; thus,
	 *  use ._serializeFiltersForGQL() for that.
	 * Note: This method does not work for functions, and will strip out any methods inside
	 *  the passed object.
	 * @param {Object} jsonObject - The JSON object (or array) to serialize for GQL.
	 * @return {string|boolean} The serialized object without quotes around the object key names.
	 * If an invalid JSON object (such as a function) is passed in, then the boolean false
	 *  is returned.
	 * @private
	 */
	_serializeObjectForGQL: function(jsonObject) {
		var i, propName, strConvertedObject, workingString;
		var arrConvertedObject = [];
		if (typeof jsonObject === 'function') {
			return false;
		}
		if (typeof jsonObject !== 'object') {
			// not an object, stringify using native function
			return JSON.stringify(jsonObject);
		}
		if (Array.isArray(jsonObject)) {
			//workingString = '[';
			for (i = 0; i < jsonObject.length; i++) {
				workingString = this._serializeObjectForGQL(jsonObject[i]);
				if (workingString) {
					arrConvertedObject.push(workingString);
				}
			}
			strConvertedObject = '[' + arrConvertedObject.join(',') + ']';
			return strConvertedObject;
		}
		// Implements recursive object serialization according to JSON spec
		// but without quotes around the keys.
		for (propName in jsonObject) {
			//Prevent iteration into non-own properties
			if (!jsonObject.hasOwnProperty(propName)) {
				continue;
			}
			workingString = this._serializeObjectForGQL(jsonObject[propName]);
			if (workingString) {
				arrConvertedObject.push(propName + ':' + workingString);
			}
		}
		strConvertedObject = '{' + arrConvertedObject.join(',') + '}';
		return strConvertedObject;
	},
	/**
	 * @param filtersArr
	 * @return {string}
	 * @private
	 */
	_serializeFiltersForGQL: function(filtersArr) {
		var i, filterObject;
		var serializedFilterArr = [];
		for (i = 0; i < filtersArr.length; i++) {
			filterObject = filtersArr[i];
			//upcoming_feature: Add "all" node?
			serializedFilterArr.push('{path:"' + filterObject.path + '",op:' +
				filterObject.op.toUpperCase() + ',value:"' + filterObject.value +
				'",negated:' + !!filterObject.negated + '}');
		}
		return '[' + serializedFilterArr.join(',') + ']';
	},

	/**
	 * upcoming_feature: Update this method to support multi-row sensors mixed in with single-row sensors without breaking the entire response object (or returning multi-row sensors as though they were entirely separate records).
	 * @param gQuestionResponse
	 * @param {boolean} [removeNoResultRows=true] - If true, rows with "[no results]" will be removed.
	 * @returns {{columns: *[], rows: *[]}}
	 * @private
	 */
	_transformGatewayQueryResponse: function(gQuestionResponse, removeNoResultRows) {
		var iColumn, columnName, iRow, responseColumns, responseRows;
		var transformedData = {
			'columns': [],
			'rows': []
		};

		removeNoResultRows = (typeof removeNoResultRows !== 'undefined') ? !!removeNoResultRows : true;

		//Check for incomplete response
		if (
			!gQuestionResponse.hasOwnProperty('data') ||
			!gQuestionResponse.data.hasOwnProperty('endpoints') ||
			!gQuestionResponse.data.endpoints.hasOwnProperty('edges') ||
			!gQuestionResponse.data.endpoints.edges.length > 0 ||
			!gQuestionResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!gQuestionResponse.data.endpoints.edges[0].node.hasOwnProperty('sensorReadings') ||
			!gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.hasOwnProperty('columns') ||
			!gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.columns.length > 0
		) {
			return transformedData;
		}
		responseColumns = gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.columns;
		for (iColumn = 0; iColumn < responseColumns.length; iColumn++) {
			if (
				!responseColumns[iColumn].hasOwnProperty('name') ||
				!responseColumns[iColumn].name ||
				!responseColumns[iColumn].hasOwnProperty('values') ||
				!responseColumns[iColumn].values.length > 0
			) {
				//If data for this row/column isn't valid, then skip to the next one.
				continue;
			}

			columnName = responseColumns[iColumn].name;
			responseRows = removeNoResultRows ?
				this._removeNoResultRows(responseColumns[iColumn].values) :
				responseColumns[iColumn].values;

			if (responseRows.length === 0) {
				//If data for this row isn't available, then skip to the next one.
				continue;
			}

			transformedData.columns.push(columnName);

			for (iRow = 0; iRow < responseRows.length; iRow++) {
				if (!transformedData.rows[iRow]) { //If row object hasn't been created, create it.
					transformedData.rows[iRow] = {};
				}

				transformedData.rows[iRow][columnName] = responseRows[iRow];
			}
		}
		return transformedData;
	},

	/**
	 *
	 * @param gQuestionResponse
	 *
	 * @param {boolean} [removeNoResultRows=true] - If true, rows with "[no results]" will be removed.
	 *
	 * @returns {{columns: *[], rows: *[]}}
	 *
	 * @private
	 */
	_transformGatewayQueryResponseV2: function(gQuestionResponse, removeNoResultRows) {
		var iColumn, columnName, iRow, responseColumns, responseRows, currentRowObj;
		var transformedData = {
			'columns': [],
			'rows': []
		};

		removeNoResultRows = (typeof removeNoResultRows !== 'undefined') ? !!removeNoResultRows : true;

		//Check for incomplete response
		if (
			!gQuestionResponse.hasOwnProperty('data') ||
			!gQuestionResponse.data.hasOwnProperty('endpoints') ||
			!gQuestionResponse.data.endpoints.hasOwnProperty('edges') ||
			!gQuestionResponse.data.endpoints.edges.length > 0 ||
			!gQuestionResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!gQuestionResponse.data.endpoints.edges[0].node.hasOwnProperty('sensorReadings') ||
			!gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.hasOwnProperty('columns') ||
			!gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.columns.length > 0
		) {
			return transformedData;
		}
		responseColumns = gQuestionResponse.data.endpoints.edges[0].node.sensorReadings.columns;
		for (iColumn = 0; iColumn < responseColumns.length; iColumn++) {
			if (
				!responseColumns[iColumn].hasOwnProperty('name') ||
				!responseColumns[iColumn].name ||
				!responseColumns[iColumn].hasOwnProperty('values') ||
				!responseColumns[iColumn].values.length > 0
			) {
				//If data for this row/column isn't valid, then skip to the next one.
				continue;
			}

			columnName = responseColumns[iColumn].name;
			responseRows = removeNoResultRows ?
				this._removeNoResultRows(responseColumns[iColumn].values) :
				responseColumns[iColumn].values;

			if (responseRows.length === 0) {
				//If data for this row isn't available, then skip to the next one.
				continue;
			}

			transformedData.columns.push(columnName);

			currentRowObj = {};
			//If there is only one row, then just add the value to the row object.
			currentRowObj[columnName] = (responseRows.length === 1) ? responseRows[0] : responseRows;
			transformedData.rows.push(currentRowObj);

			// transformedData.rows[iRow][columnName] = responseRows[iRow];

			// for (iRow = 0; iRow < responseRows.length; iRow++) {
			// 	if (!transformedData.rows[iRow]) { //If row object hasn't been created, create it.
			// 		transformedData.rows[iRow] = {};
			// 	}
			//
			// 	//If there is only one row, then just add the value to the row object.
			// 	if (responseRows.length === 1) {
			// 		transformedData.rows[iRow][columnName] = responseRows[iRow];
			// 		continue;
			// 	}
			// 	transformedData.rows[iRow][columnName] = responseRows[iRow];
			// }
		}
		return transformedData;
	},

	_isUsingLiveData: function() {
		return this.query_config.data_source.hasOwnProperty('ts');
	},

	_isUsingCachedData: function() {
		return this.query_config.data_source.hasOwnProperty('tds');
	},

	_removeNoResultRows: function(responseColumnValues) {
		var iValue;
		var cleanedResponseColumnValues = [];
		//Remove rows with "[no results]".
		for (iValue = 0; iValue < responseColumnValues.length; iValue++) {
			if (responseColumnValues[iValue] !== '[no results]') {
				cleanedResponseColumnValues.push(responseColumnValues[iValue]);
			}
		}

		return cleanedResponseColumnValues;
	},

	/**
	 * @param sensorName
	 * @return {GatewayQueryUtil._Sensor}
	 * @private
	 */
	_Sensor: function(sensorName) {
		this.name = sensorName;

		this.addColumn = function(columnName) {
			if (!this.hasOwnProperty('columns')) {
				this.columns = [];
			}
			this.columns.push(columnName);

			return this;
		};

		/**
		 * Add a parameter to the current sensor by the specifying the parameter's name and value.
		 * This is only necessary on sensors that require parameters.
		 * @param {String} paramName - The name of the parameter, such as "Metric".
		 * @param {String} paramValue - The value of the parameter with the specified name.
		 * @return {GatewayQueryUtil._Sensor} - This instance of the _Sensor object, so you can
		 *  chain-add multiple sensor parameters in a single statement.
		 * @example
		 * var tUtil = new x_taniu_tan_core.GatewayQueryUtil();
		 * //Only wait for one live machine matching the filter before returning response.
		 * tUtil.useLiveData(1);
		 * tUtil.addFilter('serialNumber', 'CONTAINS', 'VMware')
		 *    .addFilter('serialNumber', 'CONTAINS', '56')
		 *    .addFilter('id', 'EQ', '4');
		 * //Add several sensors, including one requiring multiple parameters.
		 * tUtil.addSensor('OS Platform');
		 * tUtil.addSensor('Computer Name');
		 * tUtil.addSensor('Performance - Top Process Metric Analysis')
		 *    .addParam('Number', '1')
		 *    .addParam('Metric', 'CPU Total')
		 *    .addParam('Analysis', 'Quantile')
		 *    .addParam('Hours', '24')
		 *    .addParam('Quantile', '0')
		 *    .addParam('Normalize', '0');
		 *
		 * gs.debug(
		 *    JSON.stringify(
		 *       tUtil.getNextPage(), null, 2
		 *    )
		 * );
		 */
		this.addParam = function(paramName, paramValue) {
			var i;
			//If params array hasn't been created, create it.
			if (!this.hasOwnProperty('params')) {
				this.params = [];
			}
			//Check for duplicates
			for (i = 0; i < this.params.length; i++) {
				//If duplicate is found, log an error. Don't add the param. Return this scope.
				if (paramName === this.params[i].name) {
					gs.error(
						'Attempted to add Tanium sensor Parameter "' + paramName +
						'" to sensor "' + this.name + '". However, that sensor already ' +
						'contains a parameter with that name.\n' +
						'Skipping adding the parameter, and returning the original sensor object.'
					);
					return this;
				}
			}
			//Add param
			this.params.push({
				'name': paramName,
				'value': paramValue.toString() //.toString() added in v1.4.0 to ensure that all sensor parameters are strings to work around a bug in APIGW.
			});
			return this;
		};
		//Return this object for chaining .addParam() calls.
		return this;
	},


	_initGatewayConfigIfEmpty: function() {
		if (typeof this.query_config === 'undefined') {
			this.query_config = {
				'exclude_errors': false, //Default to false. Set by calling .excludeErrors(). Used when setting the data source.
				'exclude_no_results': false, //Default to false. Set by calling .excludeNoResults(). Used when setting the data source.
				'include_filter': false,
				'filters': [],
				'refresh_token': null,
				'page_info': {
					'page_size': null, //Default to null. Set by calling .setPageSize().
					'previous_page_start_cursor': null,
					'previous_page_end_cursor': null,
					'has_next_page': true,
					'has_previous_page': false
				},
				'sensors_to_read': [],
				'expected_count': 0,
				'data_source': {
					'ts': {
						'excludeErrors': false,
						'excludeNoResults': false
					} //ts: live data, tds: cached data
				}
			};
		}
	},
	type: 'GatewayQueryUtil'
});
